"""OpenAI streaming + tool calls.

Stream pattern:
  1. Open stream with tools available
  2. Yield content chunks as they arrive
  3. When tool_call complete, pause stream, run tool, feed result back
  4. Resume stream with tool output appended to conversation
  5. Continue yielding until completion

This is more involved than non-streaming because tool_calls arrive in deltas
that must be assembled.
"""
from __future__ import annotations

import json
import os
from typing import Iterator

from openai import OpenAI

client = OpenAI()


TOOLS = [{
    "type": "function",
    "function": {
        "name": "get_weather",
        "description": "Get weather for a location",
        "parameters": {
            "type": "object",
            "properties": {"location": {"type": "string"}},
            "required": ["location"],
        },
    },
}]


def get_weather(location: str) -> dict:
    return {"location": location, "temp": 22, "condition": "sunny"}


TOOL_IMPL = {"get_weather": get_weather}


def stream_with_tools(user_message: str, *, model: str = "gpt-4o-mini") -> Iterator[dict]:
    """Yield events: {'type': 'text', 'content': '...'} or {'type': 'tool_call', 'name': ..., 'args': ..., 'result': ...}."""

    messages: list[dict] = [
        {"role": "user", "content": user_message},
    ]

    for _ in range(5):  # max iterations
        stream = client.chat.completions.create(
            model=model,
            messages=messages,
            tools=TOOLS,
            stream=True,
        )

        # Accumulators
        assistant_text = ""
        tool_calls: list[dict] = []  # built up from deltas

        for chunk in stream:
            delta = chunk.choices[0].delta

            # Text content
            if delta.content:
                assistant_text += delta.content
                yield {"type": "text", "content": delta.content}

            # Tool call deltas (assembled incrementally)
            if delta.tool_calls:
                for tc_delta in delta.tool_calls:
                    idx = tc_delta.index
                    # Extend list if needed
                    while len(tool_calls) <= idx:
                        tool_calls.append({"id": "", "name": "", "arguments": ""})
                    if tc_delta.id:
                        tool_calls[idx]["id"] = tc_delta.id
                    if tc_delta.function:
                        if tc_delta.function.name:
                            tool_calls[idx]["name"] += tc_delta.function.name
                        if tc_delta.function.arguments:
                            tool_calls[idx]["arguments"] += tc_delta.function.arguments

        # Append assistant message
        assistant_msg = {"role": "assistant", "content": assistant_text or None}
        if tool_calls:
            assistant_msg["tool_calls"] = [
                {"id": tc["id"], "type": "function", "function": {"name": tc["name"], "arguments": tc["arguments"]}}
                for tc in tool_calls
            ]
        messages.append(assistant_msg)

        # If no tool calls, we're done
        if not tool_calls:
            return

        # Execute tools and feed results
        for tc in tool_calls:
            try:
                args = json.loads(tc["arguments"])
            except json.JSONDecodeError:
                args = {}
            fn = TOOL_IMPL.get(tc["name"])
            result = fn(**args) if fn else {"error": f"unknown tool {tc['name']}"}
            yield {"type": "tool_call", "name": tc["name"], "args": args, "result": result}
            messages.append({
                "role": "tool",
                "tool_call_id": tc["id"],
                "content": json.dumps(result, default=str),
            })

        # Loop: continue stream until completion without tool_calls


# ----------------- DEMO -----------------

if __name__ == "__main__":
    for event in stream_with_tools("What's the weather in Tokyo? Then summarize."):
        if event["type"] == "text":
            print(event["content"], end="", flush=True)
        elif event["type"] == "tool_call":
            print(f"\n[tool_call: {event['name']}({event['args']}) → {event['result']}]")
    print()

"""Tool-call validation loop.

For each tool result:
  1. Validate against expected schema (Pydantic).
  2. If invalid: format error back to model, ask for corrected call.
  3. Retry up to N times.
  4. If still invalid: surface error to user, don't crash.

Useful for tools that:
  - Hit third-party APIs with inconsistent shapes
  - Run user-provided code (e.g., SQL queries)
  - Compute heavily and may run out of time / return partial results
"""
from __future__ import annotations

import json
from typing import Any, Callable

from openai import OpenAI
from pydantic import BaseModel, Field, ValidationError

client = OpenAI()


# ----------------- TOOL OUTPUT SCHEMAS -----------------

class WeatherResult(BaseModel):
    location: str
    temp_celsius: float = Field(ge=-100, le=100)
    condition: str
    humidity_pct: int | None = Field(default=None, ge=0, le=100)


class SearchResult(BaseModel):
    query: str
    results: list[dict] = Field(min_length=1, max_length=10)


# ----------------- TOOLS (may return inconsistent shapes!) -----------------

def fake_weather(location: str) -> dict:
    """Sometimes returns malformed data."""
    if "moon" in location.lower():
        return {"error": "no weather available on the moon"}
    return {"location": location, "temp_celsius": 22, "condition": "clear", "humidity_pct": 60}


def fake_search(query: str) -> dict:
    """Sometimes empty results."""
    if "kjdfgskldjfg" in query:
        return {"query": query, "results": []}  # invalid: min_length=1
    return {"query": query, "results": [{"title": "result 1"}]}


TOOL_REGISTRY: dict[str, tuple[Callable, type[BaseModel]]] = {
    "get_weather": (fake_weather, WeatherResult),
    "search": (fake_search, SearchResult),
}


# ----------------- VALIDATED EXECUTION -----------------

def execute_with_validation(tool_name: str, args: dict) -> dict:
    """Run tool, validate output. Returns {ok: bool, data: ..., error: ...}."""
    if tool_name not in TOOL_REGISTRY:
        return {"ok": False, "error": f"unknown tool {tool_name}"}
    fn, schema = TOOL_REGISTRY[tool_name]
    try:
        raw = fn(**args)
    except Exception as e:
        return {"ok": False, "error": f"tool execution failed: {e}"}
    try:
        validated = schema(**raw)
        return {"ok": True, "data": validated.model_dump()}
    except ValidationError as e:
        return {"ok": False, "error": f"validation error: {e.errors()}", "raw": raw}


# ----------------- AGENT LOOP WITH RETRY -----------------

TOOL_DEFINITIONS = [
    {"type": "function", "function": {
        "name": "get_weather",
        "description": "Get weather for a location",
        "parameters": {"type": "object", "properties": {"location": {"type": "string"}}, "required": ["location"]},
    }},
    {"type": "function", "function": {
        "name": "search",
        "description": "Search results for a query",
        "parameters": {"type": "object", "properties": {"query": {"type": "string"}}, "required": ["query"]},
    }},
]


def run_agent(user_message: str, *, max_iters: int = 6, max_retries_per_tool: int = 2) -> str:
    messages = [{"role": "user", "content": user_message}]
    retries: dict[str, int] = {}  # per-tool-call retry count

    for _ in range(max_iters):
        resp = client.chat.completions.create(
            model="gpt-4o-mini",
            messages=messages,
            tools=TOOL_DEFINITIONS,
            temperature=0,
        )
        msg = resp.choices[0].message
        if not msg.tool_calls:
            return msg.content

        messages.append(msg.model_dump())
        for tc in msg.tool_calls:
            args = json.loads(tc.function.arguments)
            result = execute_with_validation(tc.function.name, args)

            if result["ok"]:
                messages.append({
                    "role": "tool",
                    "tool_call_id": tc.id,
                    "content": json.dumps(result["data"]),
                })
            else:
                # Track retries for THIS specific tool call
                key = f"{tc.function.name}::{tc.function.arguments}"
                retries[key] = retries.get(key, 0) + 1
                if retries[key] > max_retries_per_tool:
                    # Give up; surface error
                    messages.append({
                        "role": "tool",
                        "tool_call_id": tc.id,
                        "content": json.dumps({
                            "error": "tool repeatedly returned invalid data",
                            "details": result.get("error"),
                        }),
                    })
                else:
                    # Retry by feeding error back
                    messages.append({
                        "role": "tool",
                        "tool_call_id": tc.id,
                        "content": json.dumps({
                            "validation_error": result.get("error"),
                            "raw_output": result.get("raw"),
                            "instruction": "Re-call the tool with corrected arguments OR pick a different tool. If you need user input, ask the user.",
                        }),
                    })
    return "ERROR: max iterations exceeded"


if __name__ == "__main__":
    # Normal case
    print(run_agent("What's the weather in Tokyo?"))
    # Error case — moon
    print(run_agent("What's the weather on the moon?"))
    # Empty result
    print(run_agent("Search for kjdfgskldjfg"))

"""OpenAI parallel tool calls + concurrent execution."""
from __future__ import annotations

import asyncio
import json
import os
from openai import AsyncOpenAI


client = AsyncOpenAI(api_key=os.environ["OPENAI_API_KEY"])


# ----------------- TOOL IMPLEMENTATIONS (async I/O) -----------------

async def get_weather(location: str) -> dict:
    """Stub — pretend this is a real async HTTP call."""
    await asyncio.sleep(0.5)
    return {"location": location, "temp_c": 22, "conditions": "clear"}


async def get_air_quality(location: str) -> dict:
    await asyncio.sleep(0.4)
    return {"location": location, "aqi": 35, "category": "good"}


async def get_traffic(origin: str, destination: str) -> dict:
    await asyncio.sleep(0.6)
    return {"origin": origin, "destination": destination, "minutes": 18, "incidents": 0}


TOOL_REGISTRY = {
    "get_weather": get_weather,
    "get_air_quality": get_air_quality,
    "get_traffic": get_traffic,
}


# ----------------- TOOL DEFINITIONS -----------------

TOOLS = [
    {
        "type": "function",
        "function": {
            "name": "get_weather",
            "description": "Get current weather for a location.",
            "parameters": {
                "type": "object",
                "properties": {"location": {"type": "string"}},
                "required": ["location"],
            },
        },
    },
    {
        "type": "function",
        "function": {
            "name": "get_air_quality",
            "description": "Get current air quality index for a location.",
            "parameters": {
                "type": "object",
                "properties": {"location": {"type": "string"}},
                "required": ["location"],
            },
        },
    },
    {
        "type": "function",
        "function": {
            "name": "get_traffic",
            "description": "Get traffic conditions between two locations.",
            "parameters": {
                "type": "object",
                "properties": {
                    "origin": {"type": "string"},
                    "destination": {"type": "string"},
                },
                "required": ["origin", "destination"],
            },
        },
    },
]


# ----------------- EXECUTE PARALLEL -----------------

async def execute_tool_call(call) -> dict:
    """Execute one tool call; return {tool_call_id, content}."""
    name = call.function.name
    try:
        args = json.loads(call.function.arguments)
        fn = TOOL_REGISTRY.get(name)
        if not fn:
            return {"tool_call_id": call.id, "content": f"Unknown tool: {name}"}
        result = await fn(**args)
        return {"tool_call_id": call.id, "content": json.dumps(result)}
    except Exception as e:
        return {"tool_call_id": call.id, "content": f"Error: {e}"}


async def execute_parallel(tool_calls) -> list[dict]:
    """Run all tool calls concurrently."""
    return await asyncio.gather(*[execute_tool_call(c) for c in tool_calls])


# ----------------- AGENT LOOP -----------------

async def agent(user_message: str, max_iterations: int = 5):
    messages = [{"role": "user", "content": user_message}]

    for _ in range(max_iterations):
        resp = await client.chat.completions.create(
            model="gpt-4o",
            messages=messages,
            tools=TOOLS,
            parallel_tool_calls=True,  # default; set False to force sequential
            temperature=0.0,
        )
        msg = resp.choices[0].message
        messages.append(msg.model_dump(exclude_none=True))

        if not msg.tool_calls:
            return msg.content

        print(f"Executing {len(msg.tool_calls)} tool calls in parallel...")
        results = await execute_parallel(msg.tool_calls)
        for r in results:
            messages.append({"role": "tool", **r})

    return "Max iterations reached"


# ----------------- DEMO -----------------

if __name__ == "__main__":
    import time
    start = time.time()
    result = asyncio.run(agent(
        "What's the weather, air quality, and traffic from SFO to downtown San Francisco? Compare."
    ))
    print(f"\nResult: {result}")
    print(f"Total: {time.time() - start:.2f}s")

"""Groq LPU streaming chat with OpenAI fallback + latency telemetry."""
import os, time, logging
from groq import Groq, APIError as GroqError
from openai import OpenAI

groq_client = Groq(api_key=os.environ['GROQ_API_KEY'])
openai_client = OpenAI()  # fallback
log = logging.getLogger(__name__)

GROQ_MODEL = 'llama-3.3-70b-versatile'
FALLBACK_MODEL = 'gpt-4o-mini'

def stream_chat(messages: list[dict], max_tokens: int = 500) -> dict:
    """Stream a chat response. Returns dict with text + telemetry."""
    start = time.time()
    ttft = None
    chunks = []
    provider = 'groq'
    try:
        stream = groq_client.chat.completions.create(
            model=GROQ_MODEL, messages=messages, stream=True, max_tokens=max_tokens,
        )
        for chunk in stream:
            if chunk.choices[0].delta.content:
                if ttft is None:
                    ttft = (time.time() - start) * 1000
                chunks.append(chunk.choices[0].delta.content)
    except GroqError as e:
        log.warning('Groq error, falling back to OpenAI: %s', e)
        provider = f'openai-fallback (groq: {type(e).__name__})'
        ttft = chunks = None  # reset for fallback
        start = time.time(); chunks = []; ttft = None
        stream = openai_client.chat.completions.create(
            model=FALLBACK_MODEL, messages=messages, stream=True, max_tokens=max_tokens,
        )
        for chunk in stream:
            if chunk.choices[0].delta.content:
                if ttft is None:
                    ttft = (time.time() - start) * 1000
                chunks.append(chunk.choices[0].delta.content)
    end = time.time()
    text = ''.join(chunks)
    return {
        'text': text,
        'provider': provider,
        'ttft_ms': round(ttft or 0, 1),
        'total_ms': round((end - start) * 1000, 1),
        'tokens_estimated': len(text.split()) * 1.3,
    }

if __name__ == '__main__':
    result = stream_chat([{'role': 'user', 'content': 'Explain LPU vs GPU in one paragraph.'}])
    print(f"provider={result['provider']} ttft={result['ttft_ms']}ms total={result['total_ms']}ms")
    print(result['text'])

