"""Gemini with grounded web search.

The model is allowed to perform Google searches as a tool; responses
come back with grounding metadata listing the sources.
"""
from __future__ import annotations

import os
import sys

from google import genai
from google.genai import types

client = genai.Client(api_key=os.environ["GOOGLE_API_KEY"])


def grounded_answer(query: str, *, model: str = "gemini-1.5-pro-latest") -> dict:
    """Returns dict with answer text + citations."""
    grounding_tool = types.Tool(
        google_search=types.GoogleSearch()  # enables grounded search
    )

    config = types.GenerateContentConfig(
        tools=[grounding_tool],
        temperature=0,
    )

    response = client.models.generate_content(
        model=model,
        contents=query,
        config=config,
    )

    # Extract citations from grounding metadata
    citations = []
    if response.candidates and response.candidates[0].grounding_metadata:
        meta = response.candidates[0].grounding_metadata
        if meta.grounding_chunks:
            for chunk in meta.grounding_chunks:
                if chunk.web:
                    citations.append({
                        "title": chunk.web.title,
                        "url": chunk.web.uri,
                    })

    return {
        "answer": response.text,
        "citations": citations,
        "search_queries_used": (
            meta.web_search_queries if response.candidates and response.candidates[0].grounding_metadata else []
        ),
    }


if __name__ == "__main__":
    query = sys.argv[1] if len(sys.argv) > 1 else "What are the most recent OSS AI tools released in 2026?"
    result = grounded_answer(query)
    print("\n=== ANSWER ===")
    print(result["answer"])
    print("\n=== CITATIONS ===")
    for c in result["citations"]:
        print(f"- {c['title']}: {c['url']}")
    print("\n=== SEARCH QUERIES USED ===")
    for q in result["search_queries_used"]:
        print(f"- {q}")

"""Anthropic Messages API: tools + streaming + parallel calls."""
from __future__ import annotations

import json
import os
from anthropic import Anthropic


client = Anthropic(api_key=os.environ["ANTHROPIC_API_KEY"])


# ----------------- TOOL DEFINITIONS -----------------

TOOLS = [
    {
        "name": "get_weather",
        "description": "Get current weather for a location.",
        "input_schema": {
            "type": "object",
            "properties": {
                "location": {"type": "string", "description": "City and country"},
                "unit": {"type": "string", "enum": ["c", "f"], "default": "c"},
            },
            "required": ["location"],
        },
    },
    {
        "name": "lookup_flight",
        "description": "Find flights between two airports on a given date.",
        "input_schema": {
            "type": "object",
            "properties": {
                "origin": {"type": "string"},
                "destination": {"type": "string"},
                "date": {"type": "string", "description": "YYYY-MM-DD"},
            },
            "required": ["origin", "destination", "date"],
        },
    },
]


# ----------------- TOOL EXECUTION -----------------

def execute_tool(name: str, args: dict) -> str:
    """Real implementation; return string (Anthropic expects str/list content)."""
    if name == "get_weather":
        return json.dumps({"temp": 22, "unit": args.get("unit", "c"), "conditions": "clear"})
    if name == "lookup_flight":
        return json.dumps({"flights": [{"id": "AA101", "depart": "08:00", "price": 320}]})
    return json.dumps({"error": f"unknown tool {name}"})


# ----------------- AGENT LOOP WITH STREAMING -----------------

def run_agent(user_message: str, max_iterations: int = 6) -> str:
    """Run agent: stream tokens, handle tool calls, loop until stop."""
    messages = [{"role": "user", "content": user_message}]
    text_parts: list[str] = []

    for iteration in range(max_iterations):
        # Stream the response so we can show tokens AS they arrive
        with client.messages.stream(
            model="claude-3-5-sonnet-20241022",
            max_tokens=2048,
            tools=TOOLS,
            messages=messages,
        ) as stream:
            for text in stream.text_stream:
                print(text, end="", flush=True)
                text_parts.append(text)

            final = stream.get_final_message()

        # Append assistant turn to messages
        messages.append({"role": "assistant", "content": final.content})

        if final.stop_reason == "end_turn":
            print()  # newline
            return "".join(text_parts)

        if final.stop_reason == "tool_use":
            # Execute all tool_use blocks (can be parallel — multiple in one turn)
            tool_results = []
            for block in final.content:
                if block.type == "tool_use":
                    try:
                        result = execute_tool(block.name, block.input)
                        tool_results.append({
                            "type": "tool_result",
                            "tool_use_id": block.id,
                            "content": result,
                        })
                    except Exception as e:
                        tool_results.append({
                            "type": "tool_result",
                            "tool_use_id": block.id,
                            "content": f"Error: {e}",
                            "is_error": True,
                        })
            messages.append({"role": "user", "content": tool_results})
            continue

        # max_tokens or other stop: surface
        raise RuntimeError(f"Unexpected stop_reason: {final.stop_reason}")

    raise RuntimeError(f"Max iterations ({max_iterations}) reached")


if __name__ == "__main__":
    result = run_agent("What's the weather in Lisbon, and are there flights from JFK tomorrow?")
    print(f"\n--- FINAL ---\n{result}")

"""LiteLLM Router with fallbacks, load-balancing, and per-route limits."""
from __future__ import annotations

import os
from litellm import Router


# ----------------- MODEL LIST -----------------

# Each entry is a "deployment" of a logical model_group_name.
# Router picks one per call; falls back to another on failure.
model_list = [
    {
        "model_name": "smart-model",  # logical name your app uses
        "litellm_params": {
            "model": "anthropic/claude-3-5-sonnet-20241022",
            "api_key": os.environ["ANTHROPIC_API_KEY"],
            "rpm": 50,  # per-deployment rate limit
        },
    },
    {
        "model_name": "smart-model",
        "litellm_params": {
            "model": "openai/gpt-4o",
            "api_key": os.environ["OPENAI_API_KEY"],
            "rpm": 100,
        },
    },
    {
        "model_name": "smart-model",
        "litellm_params": {
            "model": "bedrock/anthropic.claude-3-5-sonnet-20240620-v1:0",
            "aws_region_name": "us-east-1",
            "rpm": 30,
        },
    },
    {
        "model_name": "cheap-model",
        "litellm_params": {
            "model": "openai/gpt-4o-mini",
            "api_key": os.environ["OPENAI_API_KEY"],
            "rpm": 500,
        },
    },
    {
        "model_name": "cheap-model",
        "litellm_params": {
            "model": "anthropic/claude-3-5-haiku-20241022",
            "api_key": os.environ["ANTHROPIC_API_KEY"],
            "rpm": 200,
        },
    },
]


# ----------------- ROUTER -----------------

router = Router(
    model_list=model_list,
    routing_strategy="latency-based-routing",  # or "least-busy", "usage-based-routing"
    fallbacks=[
        {"smart-model": ["cheap-model"]},   # if smart-model fails, try cheap-model
    ],
    num_retries=2,
    timeout=30,
    retry_after=2,
    # Set spend tracking
    set_verbose=True,
)


# ----------------- USE -----------------

def generate(prompt: str, model_group: str = "smart-model") -> str:
    response = router.completion(
        model=model_group,
        messages=[{"role": "user", "content": prompt}],
    )
    return response.choices[0].message.content


def stream(prompt: str, model_group: str = "smart-model"):
    response = router.completion(
        model=model_group,
        messages=[{"role": "user", "content": prompt}],
        stream=True,
    )
    for chunk in response:
        delta = chunk.choices[0].delta.content
        if delta:
            print(delta, end="", flush=True)
    print()


# ----------------- COST TRACKING -----------------

def get_spend():
    """Sum spend across all deployments."""
    return router.get_total_spend()


if __name__ == "__main__":
    print(generate("Explain rate limiting in 1 paragraph."))
    print()
    stream("Write a haiku about caching.")
    print(f"\nTotal spend so far: ${get_spend():.4f}")

"""Bedrock Converse API + Guardrails.

Unified API: Claude, Llama 3, Mistral, Cohere — same Converse signature.
Guardrails apply pre-request + post-response.
"""
from __future__ import annotations

import os
import boto3


bedrock_runtime = boto3.client(service_name="bedrock-runtime",
                                region_name=os.environ.get("AWS_REGION", "us-east-1"))
bedrock = boto3.client(service_name="bedrock",
                       region_name=os.environ.get("AWS_REGION", "us-east-1"))


# ----------------- CREATE A GUARDRAIL -----------------

def ensure_guardrail() -> str:
    """Create a guardrail that blocks topic 'medical advice' + redacts PII.

    Returns guardrail_id.
    """
    try:
        response = bedrock.create_guardrail(
            name="demo-guardrail",
            description="Block medical advice + redact PII",
            topicPolicyConfig={
                "topicsConfig": [{
                    "name": "MedicalAdvice",
                    "definition": "Diagnosis, treatment, or medication recommendations.",
                    "examples": [
                        "What dose of ibuprofen should I take?",
                        "Diagnose my symptoms",
                    ],
                    "type": "DENY",
                }],
            },
            sensitiveInformationPolicyConfig={
                "piiEntitiesConfig": [
                    {"type": "EMAIL", "action": "ANONYMIZE"},
                    {"type": "PHONE", "action": "ANONYMIZE"},
                    {"type": "US_SOCIAL_SECURITY_NUMBER", "action": "BLOCK"},
                ],
            },
            blockedInputMessaging="I can't help with that topic.",
            blockedOutputsMessaging="Response blocked by content policy.",
        )
        return response["guardrailId"]
    except bedrock.exceptions.ConflictException:
        # Already exists
        for g in bedrock.list_guardrails()["guardrails"]:
            if g["name"] == "demo-guardrail":
                return g["id"]
        raise


GUARDRAIL_ID = ensure_guardrail()


# ----------------- CONVERSE API -----------------

def chat(model_id: str, messages: list[dict], system: str | None = None) -> str:
    """Unified converse call; same signature for all Bedrock-hosted models."""
    request = {
        "modelId": model_id,
        "messages": messages,
        "inferenceConfig": {"temperature": 0.0, "maxTokens": 1024},
        "guardrailConfig": {
            "guardrailIdentifier": GUARDRAIL_ID,
            "guardrailVersion": "DRAFT",  # use a specific version for prod
            "trace": "enabled",
        },
    }
    if system:
        request["system"] = [{"text": system}]

    response = bedrock_runtime.converse(**request)

    # Check guardrail trace
    if "trace" in response and "guardrail" in response["trace"]:
        trace = response["trace"]["guardrail"]
        if trace.get("inputAssessment"):
            print(f"Guardrail input trace: {trace['inputAssessment']}")
        if trace.get("outputAssessment"):
            print(f"Guardrail output trace: {trace['outputAssessment']}")

    return response["output"]["message"]["content"][0]["text"]


# ----------------- DEMO ACROSS MODELS -----------------

if __name__ == "__main__":
    msg = [{"role": "user", "content": [{"text": "What is rate limiting? My email is foo@bar.com"}]}]

    for model_id in [
        "anthropic.claude-3-5-sonnet-20240620-v1:0",
        "meta.llama3-70b-instruct-v1:0",
        "mistral.mistral-large-2402-v1:0",
    ]:
        print(f"\n=== {model_id} ===")
        try:
            print(chat(model_id, msg))
        except Exception as e:
            print(f"FAILED: {e}")

"""Mistral La Plateforme: chat, function calling, JSON mode."""
from __future__ import annotations

import os
import json
from mistralai import Mistral


client = Mistral(api_key=os.environ["MISTRAL_API_KEY"])


# ----------------- BASIC CHAT -----------------

def chat(prompt: str, model: str = "mistral-large-latest") -> str:
    response = client.chat.complete(
        model=model,
        messages=[{"role": "user", "content": prompt}],
        temperature=0.0,
    )
    return response.choices[0].message.content


# ----------------- STREAMING -----------------

def chat_stream(prompt: str, model: str = "mistral-large-latest"):
    for chunk in client.chat.stream(
        model=model,
        messages=[{"role": "user", "content": prompt}],
    ):
        delta = chunk.data.choices[0].delta.content
        if delta:
            print(delta, end="", flush=True)
    print()


# ----------------- JSON MODE -----------------

def chat_json(prompt: str) -> dict:
    response = client.chat.complete(
        model="mistral-large-latest",
        messages=[
            {"role": "system", "content": "Output JSON only."},
            {"role": "user", "content": prompt},
        ],
        response_format={"type": "json_object"},
        temperature=0,
    )
    return json.loads(response.choices[0].message.content)


# ----------------- FUNCTION CALLING -----------------

TOOLS = [
    {
        "type": "function",
        "function": {
            "name": "get_weather",
            "description": "Get current weather for a location.",
            "parameters": {
                "type": "object",
                "properties": {
                    "location": {"type": "string"},
                    "unit": {"type": "string", "enum": ["c", "f"]},
                },
                "required": ["location"],
            },
        },
    },
]


def execute_tool(name: str, args: dict) -> str:
    if name == "get_weather":
        return json.dumps({"temp": 22, "conditions": "clear"})
    return json.dumps({"error": "unknown tool"})


def chat_with_tools(prompt: str) -> str:
    messages = [{"role": "user", "content": prompt}]

    for _ in range(5):
        response = client.chat.complete(
            model="mistral-large-latest",
            messages=messages,
            tools=TOOLS,
            tool_choice="auto",
        )
        msg = response.choices[0].message
        messages.append({"role": "assistant", "content": msg.content or "",
                         "tool_calls": msg.tool_calls})

        if not msg.tool_calls:
            return msg.content

        for call in msg.tool_calls:
            args = json.loads(call.function.arguments)
            result = execute_tool(call.function.name, args)
            messages.append({"role": "tool", "tool_call_id": call.id,
                             "name": call.function.name, "content": result})
    return "Max iterations"


# ----------------- CODESTRAL FOR CODE -----------------

def code_complete(prompt: str) -> str:
    """Codestral: Mistral's code-specialized model."""
    response = client.chat.complete(
        model="codestral-latest",
        messages=[{"role": "user", "content": prompt}],
        temperature=0.0,
    )
    return response.choices[0].message.content


# ----------------- PIXTRAL FOR IMAGES -----------------

def vision(prompt: str, image_url: str) -> str:
    """Pixtral: Mistral's multi-modal model."""
    response = client.chat.complete(
        model="pixtral-12b-2409",
        messages=[{
            "role": "user",
            "content": [
                {"type": "text", "text": prompt},
                {"type": "image_url", "image_url": image_url},
            ],
        }],
    )
    return response.choices[0].message.content


# ----------------- DEMO -----------------

if __name__ == "__main__":
    print(chat("Explain caching in 3 sentences."))
    print()
    chat_stream("Write a haiku about Mistral.")
    print(chat_with_tools("What's the weather in Paris in Celsius?"))
    print(code_complete("Write a Python function to merge two sorted lists."))

"""OpenRouter: one key for 100+ models via OpenAI-compatible API."""
from __future__ import annotations

import os
from openai import OpenAI


client = OpenAI(
    base_url="https://openrouter.ai/api/v1",
    api_key=os.environ["OPENROUTER_API_KEY"],
    default_headers={
        "HTTP-Referer": "https://yourapp.com",     # for rankings + analytics
        "X-Title": "Your App Name",
    },
)


# ----------------- USE ANY MODEL BY ID -----------------

MODELS = {
    "smart": "anthropic/claude-3.5-sonnet",
    "fast": "google/gemini-flash-1.5",
    "cheap": "openai/gpt-4o-mini",
    "code": "anthropic/claude-3.5-sonnet",
    "local-ish": "meta-llama/llama-3.3-70b-instruct",      # routed to fastest provider
}


def chat(prompt: str, model: str = "anthropic/claude-3.5-sonnet") -> str:
    response = client.chat.completions.create(
        model=model,
        messages=[{"role": "user", "content": prompt}],
    )
    return response.choices[0].message.content


# ----------------- ROUTING PREFERENCES -----------------

def chat_with_routing(prompt: str, model: str = "meta-llama/llama-3.3-70b-instruct") -> str:
    """OpenRouter can pick among providers for a model; configure preferences."""
    response = client.chat.completions.create(
        model=model,
        messages=[{"role": "user", "content": prompt}],
        extra_body={
            "provider": {
                "order": ["Groq", "Together", "Fireworks"],  # try in order
                "allow_fallbacks": True,
                "data_collection": "deny",                    # privacy
                # "ignore": ["DeepInfra"],
            },
            "transforms": ["middle-out"],  # context-window compression
        },
    )
    return response.choices[0].message.content


# ----------------- FUNCTION CALLING (works across providers) -----------------

import json

TOOLS = [{
    "type": "function",
    "function": {
        "name": "get_time",
        "description": "Get current UTC time.",
        "parameters": {"type": "object", "properties": {}},
    },
}]


def execute_tool(name: str, args: dict) -> str:
    if name == "get_time":
        from datetime import datetime
        return datetime.utcnow().isoformat()
    return f"unknown tool {name}"


def chat_with_tools(prompt: str, model: str = "openai/gpt-4o-mini") -> str:
    messages = [{"role": "user", "content": prompt}]
    for _ in range(5):
        response = client.chat.completions.create(
            model=model, messages=messages, tools=TOOLS,
        )
        msg = response.choices[0].message
        messages.append(msg.model_dump(exclude_none=True))
        if not msg.tool_calls:
            return msg.content
        for call in msg.tool_calls:
            args = json.loads(call.function.arguments)
            result = execute_tool(call.function.name, args)
