"""Read-only Postgres MCP server."""
from __future__ import annotations

import os
import re

import psycopg
from fastmcp import FastMCP

DB_URL = os.environ["DATABASE_URL"]
MAX_ROWS = 100
QUERY_TIMEOUT_S = 10

mcp = FastMCP("readonly-postgres")


# Block dangerous statements; only SELECT and WITH
ALLOWED_PREFIXES = ("SELECT", "WITH", "EXPLAIN")
DANGEROUS_PATTERNS = re.compile(
    r"\b(INSERT|UPDATE|DELETE|DROP|CREATE|ALTER|TRUNCATE|GRANT|REVOKE|COPY|VACUUM)\b",
    re.IGNORECASE,
)


def _validate(sql: str) -> tuple[bool, str]:
    sql_clean = sql.strip()
    if not sql_clean:
        return False, "empty query"
    first_word = sql_clean.split()[0].upper()
    if first_word not in ALLOWED_PREFIXES:
        return False, f"only {ALLOWED_PREFIXES} allowed; got {first_word}"
    if DANGEROUS_PATTERNS.search(sql_clean):
        return False, "query contains forbidden statement type"
    if "--" in sql_clean or ";" in sql_clean.rstrip(";"):
        # naive guard against statement-stacking; allow single trailing ;
        if ";" in sql_clean[:-1] if sql_clean.endswith(";") else ";" in sql_clean:
            return False, "multiple statements not allowed"
    return True, "ok"


@mcp.tool()
def list_tables() -> list[dict]:
    """List all user tables in the database.

    Returns: list of {schema, table, comment} dicts.
    """
    sql = """
    SELECT table_schema, table_name, obj_description((table_schema||'.'||table_name)::regclass) as comment
    FROM information_schema.tables
    WHERE table_schema NOT IN ('pg_catalog', 'information_schema')
    ORDER BY table_schema, table_name
    """
    with psycopg.connect(DB_URL, connect_timeout=5) as conn:
        rows = conn.execute(sql).fetchall()
    return [{"schema": r[0], "table": r[1], "comment": r[2]} for r in rows]


@mcp.tool()
def describe_table(table_name: str) -> dict:
    """Return columns + types for a table.

    Args:
        table_name: Format 'schema.table' or just 'table' (defaults to public).
    """
    if "." in table_name:
        schema, table = table_name.split(".", 1)
    else:
        schema, table = "public", table_name

    sql = """
    SELECT column_name, data_type, is_nullable, column_default
    FROM information_schema.columns
    WHERE table_schema = %s AND table_name = %s
    ORDER BY ordinal_position
    """
    with psycopg.connect(DB_URL, connect_timeout=5) as conn:
        rows = conn.execute(sql, (schema, table)).fetchall()
    return {
        "schema": schema,
        "table": table,
        "columns": [
            {"name": r[0], "type": r[1], "nullable": r[2] == "YES", "default": r[3]}
            for r in rows
        ],
    }


@mcp.tool()
def query(sql: str, *, max_rows: int = 50) -> dict:
    """Execute a SELECT query. Read-only; capped to {max_rows}.

    Args:
        sql: SQL SELECT statement. INSERT/UPDATE/DELETE etc. are rejected.
        max_rows: Max rows to return (capped at 100).
    """
    ok, reason = _validate(sql)
    if not ok:
        return {"error": reason}

    max_rows = min(max_rows, MAX_ROWS)

    try:
        with psycopg.connect(DB_URL, connect_timeout=5) as conn:
            conn.execute(f"SET statement_timeout = {QUERY_TIMEOUT_S * 1000}")
            cur = conn.execute(sql)
            rows = cur.fetchmany(max_rows)
            columns = [desc.name for desc in cur.description] if cur.description else []
            truncated = cur.fetchone() is not None
        return {
            "columns": columns,
            "rows": [list(r) for r in rows],
            "row_count": len(rows),
            "truncated": truncated,
        }
    except psycopg.errors.QueryCanceled:
        return {"error": f"query exceeded {QUERY_TIMEOUT_S}s timeout"}
    except Exception as e:
        return {"error": f"{type(e).__name__}: {e}"}


if __name__ == "__main__":
    mcp.run()

/**
 * MCP TypeScript client: connect, discover tools, call them.
 *
 * Works with stdio (subprocess) or HTTP (SSE) transports.
 */
import { Client } from "@modelcontextprotocol/sdk/client/index.js";
import { StdioClientTransport } from "@modelcontextprotocol/sdk/client/stdio.js";
import { SSEClientTransport } from "@modelcontextprotocol/sdk/client/sse.js";


// ----------------- CONNECT (stdio) -----------------

async function connectStdio(command: string, args: string[]) {
  const transport = new StdioClientTransport({ command, args });
  const client = new Client(
    { name: "demo-client", version: "1.0.0" },
    { capabilities: { tools: {}, resources: {}, prompts: {} } }
  );
  await client.connect(transport);
  return client;
}


// ----------------- CONNECT (HTTP/SSE) -----------------

async function connectHttp(url: string) {
  const transport = new SSEClientTransport(new URL(url));
  const client = new Client(
    { name: "demo-client", version: "1.0.0" },
    { capabilities: {} }
  );
  await client.connect(transport);
  return client;
}


// ----------------- DISCOVER + CALL -----------------

async function discover(client: Client) {
  const tools = await client.listTools();
  console.log("Tools:");
  for (const t of tools.tools) {
    console.log(`  - ${t.name}: ${t.description}`);
  }

  const resources = await client.listResources();
  console.log(`Resources: ${resources.resources.length}`);

  const prompts = await client.listPrompts();
  console.log(`Prompts: ${prompts.prompts.length}`);
}


async function callTool(client: Client, name: string, args: Record<string, unknown>) {
  const result = await client.callTool({ name, arguments: args });
  if (result.isError) {
    throw new Error(`Tool error: ${JSON.stringify(result.content)}`);
  }
  return result.content;
}


// ----------------- ROBUSTNESS -----------------

async function callToolWithRetry(
  client: Client,
  name: string,
  args: Record<string, unknown>,
  maxRetries = 3
) {
  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    try {
      return await callTool(client, name, args);
    } catch (e) {
      if (attempt === maxRetries) throw e;
      const backoff = 1000 * Math.pow(2, attempt);
      console.error(`Attempt ${attempt + 1} failed; retrying in ${backoff}ms`);
      await new Promise((r) => setTimeout(r, backoff));
    }
  }
}


// ----------------- DEMO -----------------

async function main() {
  // Stdio example — launch a server subprocess
  const stdioClient = await connectStdio("npx", ["-y", "@modelcontextprotocol/server-filesystem", "/tmp"]);
  await discover(stdioClient);
  const result = await callToolWithRetry(stdioClient, "list_directory", { path: "/tmp" });
  console.log("Files:", result);
  await stdioClient.close();

  // HTTP example
  // const httpClient = await connectHttp("http://localhost:3000/sse");
  // await discover(httpClient);
}

main().catch(console.error);

