"""LanceDB embedded vector store.

Files: ./data/lancedb/<table>.lance
No server. Just import and read/write.
"""
from __future__ import annotations

import lancedb
import pyarrow as pa
from sentence_transformers import SentenceTransformer

embedder = SentenceTransformer("all-MiniLM-L6-v2")


def get_db(path: str = "./data/lancedb"):
    return lancedb.connect(path)


def ensure_table(db) -> "lancedb.Table":
    if "documents" in db.table_names():
        return db.open_table("documents")
    schema = pa.schema([
        pa.field("id", pa.int64()),
        pa.field("text", pa.string()),
        pa.field("source", pa.string()),
        pa.field("vector", pa.list_(pa.float32(), 384)),  # all-MiniLM-L6-v2 is 384 dims
    ])
    return db.create_table("documents", schema=schema)


def ingest(rows: list[dict]) -> int:
    db = get_db()
    table = ensure_table(db)
    # Embed
    texts = [r["text"] for r in rows]
    vectors = embedder.encode(texts).tolist()
    for r, v in zip(rows, vectors):
        r["vector"] = v
    table.add(rows)
    return len(rows)


def query(question: str, *, k: int = 5, filter_source: str | None = None):
    db = get_db()
    table = db.open_table("documents")
    qvec = embedder.encode([question])[0].tolist()
    search = table.search(qvec).limit(k)
    if filter_source:
        search = search.where(f"source = '{filter_source}'")
    return search.to_pandas()


def create_index():
    """Build an ANN index for faster queries on large tables."""
    db = get_db()
    table = db.open_table("documents")
    table.create_index(
        vector_column_name="vector",
        index_type="IVF_PQ",                # alternatives: IVF_HNSW_SQ, FLAT
        num_partitions=256,
        num_sub_vectors=96,
    )


if __name__ == "__main__":
    ingest([
        {"id": 1, "text": "Reciprocal rank fusion combines retriever lists.", "source": "rag.md"},
        {"id": 2, "text": "HNSW is fast but RAM-heavy.", "source": "vectors.md"},
        {"id": 3, "text": "Embedded vector stores skip the server.", "source": "infra.md"},
    ])
    print(query("how do I merge retrievers?"))

"""Redis VL: vector + structured search using Redis Stack."""
from __future__ import annotations

import os
import numpy as np
from redisvl.index import SearchIndex
from redisvl.query import VectorQuery, FilterQuery, RangeQuery
from redisvl.query.filter import Tag, Num


# ----------------- INDEX SCHEMA -----------------

schema = {
    "index": {
        "name": "docs-idx",
        "prefix": "doc:",
        "key_separator": ":",
        "storage_type": "json",  # or "hash"
    },
    "fields": [
        {"name": "title", "type": "text"},
        {"name": "category", "type": "tag"},
        {"name": "tenant_id", "type": "tag"},
        {"name": "created_at", "type": "numeric"},
        {
            "name": "embedding",
            "type": "vector",
            "attrs": {
                "dims": 1536,
                "algorithm": "hnsw",
                "distance_metric": "cosine",
                "datatype": "float32",
            },
        },
    ],
}


index = SearchIndex.from_dict(
    schema,
    redis_url=os.environ.get("REDIS_URL", "redis://localhost:6379"),
)


# ----------------- INDEX SETUP -----------------

def setup():
    if not index.exists():
        index.create()
    print(f"Index: {index.name}, fields: {[f['name'] for f in schema['fields']]}")


# ----------------- LOAD DATA -----------------

def load(docs: list[dict]):
    index.load(docs)


# ----------------- VECTOR SEARCH -----------------

def search(query_vec: np.ndarray, tenant_id: str, category: str | None = None, k: int = 5):
    filter_expr = Tag("tenant_id") == tenant_id
    if category:
        filter_expr = filter_expr & (Tag("category") == category)

    query = VectorQuery(
        vector=query_vec.tolist(),
        vector_field_name="embedding",
        return_fields=["title", "category"],
        num_results=k,
        filter_expression=filter_expr,
    )
    return index.query(query)


# ----------------- TEXT-ONLY FILTER QUERY (no vector) -----------------

def filter_only(tenant_id: str, category: str):
    query = FilterQuery(
        return_fields=["title", "category"],
        filter_expression=(Tag("tenant_id") == tenant_id) & (Tag("category") == category),
    )
    return index.query(query)


# ----------------- DEMO -----------------

if __name__ == "__main__":
    setup()

    import random
    docs = [
        {
            "id": f"d{i}",
            "title": f"Document {i}",
            "category": random.choice(["billing", "tech", "general"]),
            "tenant_id": "acme",
            "created_at": 1700000000 + i * 86400,
            "embedding": np.random.random(1536).astype(np.float32).tobytes(),
        }
        for i in range(100)
    ]
    load(docs)

    query_vec = np.random.random(1536).astype(np.float32)
