"""Hybrid RAG: BM25 + dense vector + RRF. See full_code for indexing."""
from collections import defaultdict
from llama_index.core.retrievers import VectorIndexRetriever, BaseRetriever
from llama_index.retrievers.bm25 import BM25Retriever


def rrf(results, k=60):
    fused = defaultdict(float)
    nodes = {}
    for lst in results:
        for rank, nws in enumerate(lst):
            fused[nws.node.node_id] += 1.0 / (k + rank + 1)
            nodes[nws.node.node_id] = nws
    return [nodes[nid] for nid, _ in sorted(fused.items(), key=lambda kv: kv[1], reverse=True)]


class HybridRetriever(BaseRetriever):
    def __init__(self, vec, bm25, k=10):
        self.vec, self.bm25, self.k = vec, bm25, k
        super().__init__()
    def _retrieve(self, q):
        return rrf([self.vec.retrieve(q), self.bm25.retrieve(q)])[:self.k]

