"""GitHub MCP server with per-repo allow-list."""
from __future__ import annotations

import os
from typing import Any

import httpx
from mcp.server.fastmcp import FastMCP


PAT = os.environ["GITHUB_PAT"]
ALLOWED_REPOS = set(os.environ.get("GITHUB_ALLOWED_REPOS", "chadcorp/ossaihub-cron").split(","))
HEADERS = {"Authorization": f"Bearer {PAT}", "Accept": "application/vnd.github+json", "X-GitHub-Api-Version": "2022-11-28"}

mcp = FastMCP("github")


def _require_repo(repo: str) -> None:
    if repo not in ALLOWED_REPOS:
        raise ValueError(f"Repo {repo!r} is not in allow-list. Allowed: {sorted(ALLOWED_REPOS)}")


async def _req(method: str, url: str, **kw) -> dict | list:
    async with httpx.AsyncClient(timeout=30, headers=HEADERS) as c:
        r = await c.request(method, url, **kw)
        if r.status_code >= 400:
            return {"error": f"{r.status_code} {r.text[:300]}"}
        return r.json()


@mcp.tool()
async def list_issues(repo: str, state: str = "open", labels: str = "") -> Any:
    """List issues in `owner/repo`. state in {open, closed, all}; labels = comma-separated."""
    _require_repo(repo)
    params = {"state": state}
    if labels:
        params["labels"] = labels
    return await _req("GET", f"https://api.github.com/repos/{repo}/issues", params=params)


@mcp.tool()
async def create_issue(repo: str, title: str, body: str = "", labels: list[str] | None = None) -> Any:
    """Create a new issue."""
    _require_repo(repo)
    payload = {"title": title, "body": body, "labels": labels or []}
    return await _req("POST", f"https://api.github.com/repos/{repo}/issues", json=payload)


@mcp.tool()
async def comment_on_pr(repo: str, pr_number: int, body: str) -> Any:
    """Add a comment to a pull request (uses the issue comment endpoint - PRs share that namespace)."""
    _require_repo(repo)
    return await _req("POST", f"https://api.github.com/repos/{repo}/issues/{pr_number}/comments", json={"body": body})


@mcp.tool()
async def search_code(query: str, repo: str | None = None) -> Any:
    """Search code via GitHub code search. If repo is set, restrict to that repo (still must be allow-listed)."""
    if repo:
        _require_repo(repo)
        q = f"{query} repo:{repo}"
    else:
        q = f"{query} ({' '.join('repo:' + r for r in ALLOWED_REPOS)})"
    return await _req("GET", "https://api.github.com/search/code", params={"q": q, "per_page": 20})


if __name__ == "__main__":
    mcp.run()

