"""Slack MCP server: read by default, opt-in to posting."""
from __future__ import annotations

import os
import time
from typing import Any

from mcp.server.fastmcp import FastMCP
from slack_sdk.web.async_client import AsyncWebClient
from slack_sdk.errors import SlackApiError


TOKEN = os.environ["SLACK_BOT_TOKEN"]
ALLOW_POST = os.environ.get("SLACK_ALLOW_POST", "false").lower() == "true"
ALLOWED_CHANNELS = set(c.strip() for c in os.environ.get("SLACK_ALLOWED_CHANNELS", "").split(",") if c.strip())

mcp = FastMCP("slack")
client = AsyncWebClient(token=TOKEN)


async def _with_retry(coro):
    """Retry on rate-limit with the Retry-After header."""
    for attempt in range(3):
        try:
            return await coro
        except SlackApiError as e:
            if e.response.get("error") == "ratelimited":
                wait = int(e.response.headers.get("Retry-After", "1"))
                time.sleep(wait + 1)
                continue
            return {"error": str(e)}
    return {"error": "rate-limit retries exhausted"}


@mcp.tool()
async def list_channels(types: str = "public_channel") -> Any:
    """List channels. types in {public_channel, private_channel}, comma-separated."""
    res = await _with_retry(client.conversations_list(types=types, limit=200))
    if isinstance(res, dict) and res.get("error"):
        return res
    return [{"id": c["id"], "name": c["name"], "topic": c.get("topic", {}).get("value", "")} for c in res["channels"]]


@mcp.tool()
async def read_channel_history(channel: str, limit: int = 50) -> Any:
    """Read recent messages from a channel by ID. limit max 200."""
    res = await _with_retry(client.conversations_history(channel=channel, limit=min(limit, 200)))
    if isinstance(res, dict) and res.get("error"):
        return res
    return [{"ts": m["ts"], "user": m.get("user"), "text": m.get("text", ""), "thread_ts": m.get("thread_ts")} for m in res["messages"]]


@mcp.tool()
async def post_message(channel: str, text: str, thread_ts: str | None = None) -> Any:
    """Post a message. Requires SLACK_ALLOW_POST=true AND channel in SLACK_ALLOWED_CHANNELS."""
    if not ALLOW_POST:
        return {"error": "Posting is disabled. Set SLACK_ALLOW_POST=true."}
    if ALLOWED_CHANNELS and channel not in ALLOWED_CHANNELS:
        return {"error": f"Channel {channel!r} not in allow-list. Allowed: {sorted(ALLOWED_CHANNELS)}"}
    res = await _with_retry(client.chat_postMessage(channel=channel, text=text, thread_ts=thread_ts))
    if isinstance(res, dict) and res.get("error"):
        return res
    return {"ok": True, "ts": res["ts"], "channel": res["channel"]}


if __name__ == "__main__":
    mcp.run()

