"""Pydantic -> provider-specific tool schemas (OpenAI + Anthropic + Gemini)."""
from __future__ import annotations

from typing import Any, Type
from pydantic import BaseModel, Field


def _strip_titles(schema: dict) -> dict:
    """Pydantic adds 'title' fields that confuse some providers; strip them."""
    if isinstance(schema, dict):
        return {k: _strip_titles(v) for k, v in schema.items() if k != "title"}
    if isinstance(schema, list):
        return [_strip_titles(v) for v in schema]
    return schema


def _inline_defs(schema: dict) -> dict:
    """Inline $defs nested $refs - OpenAI/Anthropic prefer flat schemas."""
    defs = schema.pop("$defs", {})

    def walk(node):
        if isinstance(node, dict):
            if "$ref" in node:
                ref = node["$ref"].rsplit("/", 1)[-1]
                return walk(defs[ref])
            return {k: walk(v) for k, v in node.items()}
        if isinstance(node, list):
            return [walk(v) for v in node]
        return node

    return walk(schema)


def tool_to_openai(model: Type[BaseModel], description: str | None = None) -> dict:
    """OpenAI tools format with strict mode."""
    schema = _strip_titles(_inline_defs(model.model_json_schema()))
    # Strict mode requires every field in required + additionalProperties: false
    schema.setdefault("additionalProperties", False)
    schema["required"] = list(schema.get("properties", {}).keys())
    return {
        "type": "function",
        "function": {
            "name": model.__name__.lower(),
            "description": description or (model.__doc__ or "").strip() or model.__name__,
            "parameters": schema,
            "strict": True,
        },
    }


def tool_to_anthropic(model: Type[BaseModel], description: str | None = None) -> dict:
    """Anthropic tool_use format."""
    schema = _strip_titles(_inline_defs(model.model_json_schema()))
    return {
        "name": model.__name__.lower(),
        "description": description or (model.__doc__ or "").strip() or model.__name__,
        "input_schema": schema,
    }


def tool_to_gemini(model: Type[BaseModel], description: str | None = None) -> dict:
    """Gemini function declaration format."""
    schema = _strip_titles(_inline_defs(model.model_json_schema()))
    return {"name": model.__name__.lower(), "description": description or (model.__doc__ or "").strip(), "parameters": schema}


# --- Example tool definitions ---
class Address(BaseModel):
    """A physical address."""
    line1: str
    city: str
    country: str = Field(description="ISO 3166-1 alpha-2 country code")


class CreateOrder(BaseModel):
    """Create an order for a customer."""
    customer_email: str = Field(description="Customer's email address.")
    items: list[str]
    shipping: Address
    notes: str | None = None


if __name__ == "__main__":
    import json
    print("--- OpenAI ---")
    print(json.dumps(tool_to_openai(CreateOrder), indent=2)[:500])
    print("\n--- Anthropic ---")
    print(json.dumps(tool_to_anthropic(CreateOrder), indent=2)[:500])

