import httpx
from tenacity import retry, retry_if_exception, wait_exponential_jitter, stop_after_attempt


class RateLimited(Exception):
    def __init__(self, ra=1.0): self.retry_after_s = ra; super().__init__(f'retry {ra}s')


def should_retry(e):
    if isinstance(e, RateLimited): return True
    if isinstance(e, httpx.HTTPStatusError): return e.response.status_code in (429, 500, 502, 503, 504)
    return isinstance(e, (httpx.TimeoutException, httpx.NetworkError))


@retry(retry=retry_if_exception(should_retry), wait=wait_exponential_jitter(initial=1, max=30), stop=stop_after_attempt(5), reraise=True)
