def route_by_complexity(prompt: str) -> str:
    if len(prompt) < 100:
        model = 'meta-llama/llama-3.1-8b-instruct'  # cheap
    elif 'reason' in prompt.lower() or 'analyze' in prompt.lower():
        model = 'anthropic/claude-sonnet-4.5'        # smart
    else:
        model = 'meta-llama/llama-3.3-70b-instruct'  # mid
    r = ROUTER.chat.completions.create(model=model, messages=[{'role':'user','content':prompt}])
    print(f'cost: ${r.usage.total_cost_usd:.4f} model={model}')
    return r.choices[0].message.content

